<script setup lang="ts">
import { Head } from '@inertiajs/vue3';
import { BadgeCheck, BarChart3, CalendarDays, Check, CircleAlert, Clock3, CreditCard, Eye, Filter, Megaphone, RefreshCw, Search, Sparkles, Target, Users, X } from '@lucide/vue';
import { computed, onMounted, ref } from 'vue';
import AppShell from '../../Layouts/AppShell.vue';

const campaigns=ref<any[]>([]),loading=ref(true),busy=ref(''),error=ref(''),notice=ref(''),query=ref(''),filter=ref('all'),selected=ref<any>(),reviewNotes=ref('');
const csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'';
const api=async(url:string,options:RequestInit={})=>{const response=await fetch(url,{...options,credentials:'same-origin',headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf(),...(options.headers??{})}});const payload=await response.json().catch(()=>({}));if(!response.ok)throw new Error(payload.message||'Unable to load campaigns.');return payload.data??payload};
const load=async()=>{loading.value=true;error.value='';try{campaigns.value=await api('/api/v1/admin/campaigns')}catch(e:any){error.value=e.message}finally{loading.value=false}};
const visible=computed(()=>campaigns.value.filter(item=>(filter.value==='all'||item.status===filter.value)&&(!query.value.trim()||`${item.title} ${item.owner?.name} ${item.goal}`.toLowerCase().includes(query.value.toLowerCase()))));
const pending=computed(()=>campaigns.value.filter(item=>item.status==='pending_review').length),active=computed(()=>campaigns.value.filter(item=>item.status==='active').length),paid=computed(()=>campaigns.value.filter(item=>item.payment?.status==='paid').reduce((sum,item)=>sum+Number(item.payment.amount_cents||0),0));
const money=(cents:number)=>new Intl.NumberFormat('en-ZA',{style:'currency',currency:'ZAR',maximumFractionDigits:0}).format((cents||0)/100);
const label=(value:string)=>String(value||'unknown').replaceAll('_',' ').replace(/\b\w/g,c=>c.toUpperCase());
const date=(value:string)=>value?new Date(value).toLocaleDateString('en-ZA',{day:'numeric',month:'short',year:'numeric'}):'Not set';
const open=(item:any)=>{selected.value=item;reviewNotes.value=item.review_notes||''};
const review=async(status:'active'|'rejected')=>{if(!selected.value)return;busy.value=status;error.value='';notice.value='';try{const result=await api(`/api/v1/admin/campaigns/${selected.value.id}/review`,{method:'PATCH',body:JSON.stringify({status,review_notes:reviewNotes.value||null})});const index=campaigns.value.findIndex(item=>item.id===selected.value.id);if(index>=0)campaigns.value[index]={...campaigns.value[index],...result};notice.value=status==='active'?'Campaign approved and activated.':'Campaign returned to the advertiser with review notes.';selected.value=null}catch(e:any){error.value=e.message}finally{busy.value=''}};
onMounted(load);
</script>

<template><Head title="Campaign management"/><AppShell><main class="campaign-admin">
<header class="campaign-admin-hero"><div><span><Sparkles/> COMMERCIAL STUDIO</span><h1>Campaign management</h1><p>Review paid promotions, protect campaign quality, and keep every launch moving.</p></div><button :disabled="loading" @click="load"><RefreshCw :class="{spin:loading}"/>Refresh</button></header>
<section class="campaign-admin-stats"><article><span><Clock3/></span><div><small>WAITING FOR REVIEW</small><strong>{{pending}}</strong><p>Ready for a decision</p></div></article><article><span><Megaphone/></span><div><small>ACTIVE CAMPAIGNS</small><strong>{{active}}</strong><p>Currently delivering</p></div></article><article><span><CreditCard/></span><div><small>VERIFIED PAYMENTS</small><strong>{{money(paid)}}</strong><p>Across loaded campaigns</p></div></article><article><span><Eye/></span><div><small>TOTAL IMPRESSIONS</small><strong>{{campaigns.reduce((s,i)=>s+Number(i.impressions_count||0),0).toLocaleString()}}</strong><p>Measured campaign reach</p></div></article></section>
<p v-if="notice" class="campaign-admin-message success"><Check/>{{notice}}</p><p v-if="error" class="campaign-admin-message error"><CircleAlert/>{{error}}</p>
<div class="campaign-toolbar"><label><Search/><input v-model="query" placeholder="Search campaigns or advertisers…"/></label><div><Filter/><button v-for="item in ['all','pending_review','active','awaiting_payment','rejected']" :class="{active:filter===item}" @click="filter=item">{{label(item)}}</button></div></div>
<section v-if="loading" class="campaign-admin-empty"><RefreshCw class="spin"/><h2>Loading campaigns</h2></section>
<section v-else-if="visible.length" class="campaign-admin-list"><article v-for="item in visible" :key="item.id" @click="open(item)"><div class="campaign-type"><Megaphone/></div><div class="campaign-main"><span>{{label(item.campaign_type)}} · {{label(item.goal)}}</span><h2>{{item.title}}</h2><p>{{item.owner?.name||'Unknown advertiser'}} · {{item.owner?.email}}</p></div><i :class="`status-${item.status}`">{{label(item.status)}}</i><dl><div><dt>Budget</dt><dd>{{money(item.total_budget_cents)}}</dd></div><div><dt>Payment</dt><dd :class="{paid:item.payment?.status==='paid'}">{{label(item.payment?.status||'none')}}</dd></div><div><dt>Schedule</dt><dd>{{date(item.starts_on)}} – {{date(item.ends_on)}}</dd></div><div><dt>Results</dt><dd>{{Number(item.impressions_count||0).toLocaleString()}} views · {{Number(item.clicks_count||0).toLocaleString()}} clicks</dd></div></dl><button>Review <Eye/></button></article></section>
<section v-else class="campaign-admin-empty"><Megaphone/><h2>No matching campaigns</h2><p>Try another status or search term.</p></section>
</main>
<div v-if="selected" class="campaign-review-overlay" @click.self="selected=null"><section class="campaign-review"><header><div><span>{{label(selected.campaign_type)}}</span><h2>{{selected.title}}</h2><p>{{selected.owner?.name}} · {{selected.owner?.email}}</p></div><button @click="selected=null"><X/></button></header><div class="review-status"><i :class="`status-${selected.status}`">{{label(selected.status)}}</i><strong>{{selected.payment?.status==='paid'?'Payment verified':'Payment '+label(selected.payment?.status||'missing')}}</strong></div><p class="review-description">{{selected.description||'No campaign description was provided.'}}</p><dl class="review-details"><div><Target/><dt>Goal</dt><dd>{{label(selected.goal)}}</dd></div><div><CreditCard/><dt>Budget</dt><dd>{{money(selected.total_budget_cents)}}</dd></div><div><CalendarDays/><dt>Schedule</dt><dd>{{date(selected.starts_on)}} – {{date(selected.ends_on)}}</dd></div><div><Users/><dt>Audience</dt><dd>{{[selected.audience?.gender,selected.audience?.province].filter(Boolean).map(label).join(' · ')||'Broad audience'}}</dd></div><div><BarChart3/><dt>Performance</dt><dd>{{selected.impressions_count||0}} impressions · {{selected.clicks_count||0}} clicks</dd></div><div><BadgeCheck/><dt>Advertiser</dt><dd>{{selected.owner?.name}}</dd></div></dl><label>Review notes<textarea v-model="reviewNotes" placeholder="Add feedback for the advertiser…"/></label><footer><button @click="selected=null">Close</button><button class="reject" :disabled="!!busy" @click="review('rejected')">{{busy==='rejected'?'Saving…':'Reject with notes'}}</button><button class="approve" :disabled="!!busy||selected.payment?.status!=='paid'" @click="review('active')">{{busy==='active'?'Activating…':'Approve campaign'}}</button></footer></section></div>
</AppShell></template>

<style scoped>
