splay:flex;width:min(380px,100%);align-items:center;padding:0 .8rem;border:1px solid #dae2ec;border-radius:12px;background:#fff}.campaign-toolbar label svg{width:16px;color:#8793a3}.campaign-toolbar input{width:100%;padding:.75rem;border:0;outline:0;background:transparent}.campaign-toolbar>div{display:flex;gap:.3rem;align-items:center;overflow:auto}.campaign-toolbar>div>svg{width:16px;color:#8490a1}.campaign-toolbar button{padding:.55rem .7rem;white-space:nowrap;color:#687588;border:0;border-radius:999px;background:#eef1f5;font-size:.58rem;font-weight:800}.campaign-toolbar button.active{color:#fff;background:#476FEA}.campaign-admin-list{display:grid;gap:.7rem}.campaign-admin-list>article{display:grid;grid-template-columns:46px minmax(220px,1fr) auto;gap:.8rem;align-items:center;padding:1rem;border:1px solid #e0e6ef;border-radius:17px;background:#fff;box-shadow:0 10px 26px #1c304f0a;cursor:pointer;transition:.18s}.campaign-admin-list>article:hover{border-color:#bdcbed;transform:translateY(-2px);box-shadow:0 14px 32px #1c304f12}.campaign-type{display:grid;width:46px;height:46px;place-items:center;color:#c74484;border-radius:13px;background:#fff0f7}.campaign-type svg{width:21px}.campaign-main{display:grid;gap:.15rem}.campaign-main span{color:#7058c7;font-size:.5rem;font-weight:900;letter-spacing:.07em}.campaign-main h2{margin:0;font-size:.86rem}.campaign-main p{margin:0;color:#7b8798;font-size:.59rem}.campaign-admin-list i,.review-status i{padding:.35rem .55rem;border-radius:999px;font-size:.54rem;font-style:normal;font-weight:850}.status-active{color:#157049;background:#e7f8ef}.status-pending_review{color:#8a5e05;background:#fff3d6}.status-awaiting_payment{color:#8b536c;background:#fff0f6}.status-rejected,.status-cancelled{color:#a83252;background:#ffedf2}.campaign-admin-list dl{display:grid;grid-column:2/-1;grid-template-columns:repeat(4,1fr);gap:.45rem;margin:0}.campaign-admin-list dl>div{display:grid;gap:.1rem;padding:.55rem;border-radius:9px;background:#f6f8fb}.campaign-admin-list dt{color:#8994a4;font-size:.5rem}.campaign-admin-list dd{margin:0;font-size:.62rem;font-weight:800}.campaign-admin-list dd.paid{color:#16704a}.campaign-admin-list article>button{display:flex;grid-column:3;gap:.35rem;align-items:center;justify-content:center;padding:.5rem .7rem;color:#476FEA;border:0;border-radius:8px;background:#edf3ff;font-size:.58rem;font-weight:850}.campaign-admin-list article>button svg{width:14px}.campaign-admin-empty{display:grid;min-height:320px;place-content:center;justify-items:center;color:#7c8899;text-align:center;border:1px dashed #cbd5e2;border-radius:20px;background:#f8fafc}.campaign-admin-empty svg{width:38px}.campaign-admin-empty h2{margin:.7rem 0 .2rem;color:#263349}.campaign-admin-empty p{margin:0}.campaign-review-overlay{position:fixed;z-index:150;inset:0;display:grid;place-items:center;padding:1rem;background:#101a2a99;backdrop-filter:blur(6px)}.campaign-review{width:min(650px,100%);max-height:92vh;overflow:auto;padding:1.3rem;border-radius:21px;background:#fff;box-shadow:0 28px 80px #09111f55}.campaign-review>header{display:flex;justify-content:space-between}.campaign-review header span{color:#b63e7b;font-size:.55rem;font-weight:900;letter-spacing:.09em}.campaign-review h2{margin:.25rem 0;font-size:1.35rem}.campaign-review header p{margin:0;color:#7a8697;font-size:.65rem}.campaign-review header button{display:grid;width:34px;height:34px;place-items:center;border:0;border-radius:50%;background:#eef1f5}.campaign-review header svg{width:16px}.review-status{display:flex;gap:.6rem;align-items:center;margin:1rem 0;padding:.75rem;border-radius:12px;background:#f6f8fb}.review-status strong{font-size:.66rem}.review-description{color:#5f6c7f;font-size:.7rem;line-height:1.55}.review-details{display:grid;grid-template-columns:1fr 1fr;gap:.55rem}.review-details>div{display:grid;grid-template-columns:25px 1fr;align-items:center;padding:.7rem;border:1px solid #e4e8ef;border-radius:11px}.review-details svg{grid-row:1/3;width:16px;color:#476FEA}.review-details dt{color:#8893a3;font-size:.5rem}.review-details dd{margin:0;font-size:.63rem;font-weight:800}.campaign-review>label{display:grid;gap:.35rem;margin-top:1rem;color:#596678;font-size:.62rem;font-weight:800}.campaign-review textarea{min-height:90px;padding:.7rem;border:1px solid #d9e1eb;border-radius:10px;resize:vertical}.campaign-review footer{display:flex;gap:.5rem;justify-content:flex-end;margin-top:1rem}.campaign-review footer button{padding:.65rem .85rem;border:0;border-radius:9px;font-weight:800}.campaign-review footer .reject{color:#a83252;background:#ffedf2}.campaign-review footer .approve{color:#fff;background:#476FEA}.campaign-review footer .approve:disabled{opacity:.45}.spin{animation:spin .8s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}@media(max-width:850px){.campaign-admin{padding:1rem .85rem 6rem}.campaign-admin-stats{grid-template-columns:repeat(2,1fr)}.campaign-toolbar{align-items:stretch;flex-direction:column}.campaign-admin-list>article{grid-template-columns:44px minmax(0,1fr) auto}.campaign-admin-list dl{grid-column:1/-1;grid-template-columns:repeat(2,1fr)}}@media(max-width:560px){.campaign-admin-hero{align-items:flex-start;flex-direction:column;padding:1.4rem}.campaign-admin-hero button{width:100%;justify-content:center}.campaign-admin-stats{grid-template-columns:1fr 1fr}.campaign-admin-stats article>span{display:none}.campaign-admin-list>article{grid-template-columns:minmax(0,1fr) auto}.campaign-type{display:none}.campaign-main{grid-column:1}.campaign-admin-list article>i{grid-column:2}.campaign-admin-list article>button{grid-column:1/-1}.review-details{grid-template-columns:1fr}.campaign-review footer{align-items:stretch;flex-direction:column}}
</style>
